import React, {useState, useEffect} from 'react'
import styled from 'styled-components'
import searchImage from './static/search.png'
import shoppingCartImage from './static/shopping-cart.png'
import {useDispatch} from 'react-redux'
import {openLoginForm, handleLoginAndOut} from '../redux/accountSlice'
import {Link} from 'react-router-dom'
import {getMe} from '../WebAPI'

const NavbarWrapper = styled.div `
display:flex;
justify-content:space-between;
align-items:center;
width:90vw;
height:15vh;
margin:0 auto;
`

const BrandName = styled(Link) `
font-size:2rem;
font-weight:900;
letter-spacing:10px;
text-decoration:none;
color:#1C1C1C;
`

const SearchBarContainer = styled.div `
width:35vw;
height:5vh;
display:flex;
align-items:center;
`

const SearchBar = styled.input `
display:flex;
justify-content:flex-end;
align-items:center;
border-radius:7px;
border:1px solid grey;
padding:5px 10px;
width:100%;
box-sizing:border-box;
height:100%;
color:grey;
`

const SearchIcon = styled.div `
background-image:url(${searchImage});
background-position:center;
background-size:cover;
background-repeat:no-repeat;
width:20px;
height:20px;
position:relative;
margin-left:-30px;
`

const FeaturesWrapper = styled.div `
display:flex;
font-size:0.8rem;
font-weight:bold;
align-items:center;
justify-content:flex-end;
width:20%;
`

const Sell = styled(Link) `
margin-left:8%;
text-decoration:none;
color:#1C1C1C;
&:hover {
	cursor:pointer;
}
`

const Shop = styled(Link) `
margin-left:8%;
text-decoration:none;
color:#1C1C1C;
&:hover {
	cursor:pointer;
}
`

const Login = styled.div `
&:hover {
	cursor:pointer;
}
`

const ShoppingCart = styled(Link) `
background-image:url(${shoppingCartImage});
width:28px;
height:28px;
background-size:cover;
margin-left:8%;
&:hover {
	cursor:pointer;
}
`

const Me = styled(Link) `
border-radius:50%;
background-color:grey;
width:28px;
height:28px;
margin-left:8%;
&:hover {
	cursor:pointer;
}
`

export default function Header () {
	const dispatch = useDispatch()
	const [input, setInput] = useState('Search')


	useEffect(() => {
		const authKey = localStorage.getItem('isAuth')
		getMe(authKey)
	})

	const handleOpenLogin = () => {
		dispatch(openLoginForm())
	}

	const handleSearchInputClick = () => {
		setInput('')
	}

	const handleSearchInputChange = e => {
		setInput(e.target.value)
	}

	return (
		<NavbarWrapper>
			<BrandName to='/'>CACTUS</BrandName>
			<SearchBarContainer>
				<SearchBar value={input} onClick={handleSearchInputClick} onChange={handleSearchInputChange}></SearchBar>
				<SearchIcon></SearchIcon>
			</SearchBarContainer>
			<FeaturesWrapper>
				<Login onClick={handleOpenLogin}>LOGIN</Login>
				<Sell to='/sell'>SELL</Sell>
				<Shop to='/shop'>SHOP</Shop>
				<ShoppingCart to='/shoppingCart'></ShoppingCart>
				<Me to='/me'></Me>
			</FeaturesWrapper>
		</NavbarWrapper>
	)
}
